tests.source_program:
define nofpclass(nan ninf nzero nsub nnorm) <4 x half> @ret_positives_non_nan___shuffle_fabs(i1 %cond, <4 x half> nofpclass(ninf nzero nsub nnorm) %known.positive0, <4 x half> nofpclass(ninf nzero nsub nnorm) %known.positive1) {
  %fabs.0 = call <4 x half> @llvm.fabs.v4f16(<4 x half> %known.positive0)
  %fabs.1 = call <4 x half> @llvm.fabs.v4f16(<4 x half> %known.positive1)
  %shuffle = shufflevector <4 x half> %fabs.0, <4 x half> %fabs.1, <4 x i32> <i32 4, i32 2, i32 3, i32 0>
  ret <4 x half> %shuffle
}

